import pytest
from merge_sorted import merge_sorted


# ---------------------------------------------------------------------------
# Happy path tests
# ---------------------------------------------------------------------------

class TestHappyPath:
    def test_basic_merge(self):
        """Two simple sorted lists merge correctly."""
        assert merge_sorted([1, 3, 5], [2, 4, 6]) == [1, 2, 3, 4, 5, 6]

    def test_non_overlapping_ranges_a_before_b(self):
        """All elements of a are smaller than all elements of b."""
        assert merge_sorted([1, 2, 3], [4, 5, 6]) == [1, 2, 3, 4, 5, 6]

    def test_non_overlapping_ranges_b_before_a(self):
        """All elements of b are smaller than all elements of a."""
        assert merge_sorted([4, 5, 6], [1, 2, 3]) == [1, 2, 3, 4, 5, 6]

    def test_equal_length_lists(self):
        assert merge_sorted([1, 4, 7], [2, 5, 8]) == [1, 2, 4, 5, 7, 8]

    def test_unequal_length_a_longer(self):
        assert merge_sorted([1, 2, 3, 10], [4, 5]) == [1, 2, 3, 4, 5, 10]

    def test_unequal_length_b_longer(self):
        assert merge_sorted([4, 5], [1, 2, 3, 10]) == [1, 2, 3, 4, 5, 10]

    def test_negative_numbers(self):
        assert merge_sorted([-5, -3, -1], [-4, -2, 0]) == [-5, -4, -3, -2, -1, 0]

    def test_mixed_negative_and_positive(self):
        assert merge_sorted([-3, 0, 4], [-1, 2, 5]) == [-3, -1, 0, 2, 4, 5]

    def test_floats(self):
        assert merge_sorted([1.1, 2.2, 3.3], [1.5, 2.5, 3.5]) == [
            1.1, 1.5, 2.2, 2.5, 3.3, 3.5
        ]

    def test_strings(self):
        """Works with any comparable type, including strings."""
        assert merge_sorted(["apple", "cherry"], ["banana", "date"]) == [
            "apple", "banana", "cherry", "date"
        ]

    def test_single_element_each(self):
        assert merge_sorted([1], [2]) == [1, 2]
        assert merge_sorted([2], [1]) == [1, 2]


